svg.script:
(function () {
  var svg = document.documentElement;
  var U0 = -1.2, N = 8, UMAX = 1.5;
  var X0 = 380, XS = 200, YB = 250, YS = 84;
  var TX0 = 280, TW = 360, LRMIN = 0.01, LRMAX = 1.3;
  var dots = [], i;
  for (i = 1; i <= N; i++) dots.push(document.getElementById('s' + i));
  var traj = document.getElementById('traj'), ball = document.getElementById('ball');
  var knob = document.getElementById('knob'), tf = document.getElementById('tf');
  var ro = document.getElementById('ro'), ov = document.getElementById('ov');
  function pos(u) {
    var c = Math.max(-UMAX, Math.min(UMAX, u));
    return [X0 + XS * c, YB - YS * c * c];
  }
  function upd(t) {
    t = Math.max(0, Math.min(1, t));
    var lr = LRMIN * Math.pow(LRMAX / LRMIN, t);
    var u = U0, pts = [pos(U0)], k, p;
    for (k = 1; k <= N; k++) {
      u = u * (1 - 2 * lr);
      p = pos(u);
      dots[k - 1].setAttribute('cx', p[0]);
      dots[k - 1].setAttribute('cy', p[1]);
      pts.push(p);
    }
    traj.setAttribute('points', pts.map(function (q) { return q[0] + ',' + q[1]; }).join(' '));
    ball.setAttribute('cx', pts[N][0]);
    ball.setAttribute('cy', pts[N][1]);
    knob.setAttribute('transform', 'translate(' + (TX0 + t * TW) + ',320)');
    tf.setAttribute('width', t * TW);
    var m = 1 - 2 * lr, msg;
    if (Math.abs(m) > 1.0001) msg = 'way too large: each step lands higher — the ball leaves the bowl';
    else if (lr > 0.55) msg = 'too large: overshoots the minimum and bounces across the bowl';
    else if (Math.abs(u) > 0.3) msg = 'too small: still crawling toward the bottom after 8 steps';
    else msg = 'about right: settles at the bottom';
    ro.textContent = 'learning rate ' + lr.toFixed(2) + ' — ' + msg;
  }
  function toX(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }
  var drag = false;
  ov.addEventListener('pointerdown', function (e) { drag = true; ov.setPointerCapture(e.pointerId); upd((toX(e) - TX0) / TW); });
  ov.addEventListener('pointermove', function (e) { if (drag || e.pointerType === 'mouse') upd((toX(e) - TX0) / TW); });
  addEventListener('pointerup', function () { drag = false; });
  upd(Math.log(0.3 / LRMIN) / Math.log(LRMAX / LRMIN));
})();
